using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ───── AddItem ─────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(2, _cart.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        _cart.AddItem("SKU-1", 2, 5.00m);
        _cart.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.AreEqual(5, _cart.Items["SKU-1"].Quantity);
    }

    [TestMethod]
    public void AddItem_MultipleSkus_AllTracked()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 1, 2.00m);
        _cart.AddItem("C", 1, 3.00m);

        Assert.AreEqual(3, _cart.Items.Count);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_Throws()
        => _cart.AddItem(null!, 1, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_Throws()
        => _cart.AddItem("", 1, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_ZeroQuantity_Throws()
        => _cart.AddItem("SKU-1", 0, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativeQuantity_Throws()
        => _cart.AddItem("SKU-1", -1, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativePrice_Throws()
        => _cart.AddItem("SKU-1", 1, -5.00m);

    [TestMethod]
    public void AddItem_ZeroPrice_Allowed()
    {
        _cart.AddItem("FREEBIE", 1, 0m);
        Assert.AreEqual(0m, _cart.Items["FREEBIE"].Price);
    }

    // ───── RemoveItem ─────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovedFromCart()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.RemoveItem("SKU-1");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    [ExpectedException(typeof(KeyNotFoundException))]
    public void RemoveItem_NonexistentSku_Throws()
        => _cart.RemoveItem("MISSING");

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveItem_NullSku_Throws()
        => _cart.RemoveItem(null!);

    [TestMethod]
    public void RemoveItem_LeavesOtherItems()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 1, 2.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.IsTrue(_cart.Items.ContainsKey("B"));
    }

    // ───── CalculateTotal ─────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
        => Assert.AreEqual(0m, _cart.CalculateTotal());

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-1", 3, 10.00m);
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsCorrectly()
    {
        _cart.AddItem("A", 2, 5.00m);  // 10
        _cart.AddItem("B", 1, 7.50m);  //  7.50
        Assert.AreEqual(17.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_Recalculates()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ───── ApplyCoupon ─────

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
        Assert.AreEqual("SAVE10", _cart.AppliedCoupon);
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        _cart.AddItem("SKU-1", 1, 50.00m);
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Half_Applies50PercentDiscount()
    {
        _cart.AddItem("SKU-1", 2, 30.00m);
        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_UnknownCode_Throws()
        => _cart.ApplyCoupon("BOGUS");

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws()
        => _cart.ApplyCoupon("");

    [TestMethod]
    public void ApplyCoupon_ReplacePreviousCoupon()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
        Assert.AreEqual("SAVE20", _cart.AppliedCoupon);
    }

    [TestMethod]
    public void CalculateTotal_WithCoupon_RoundsCorrectly()
    {
        _cart.AddItem("SKU-1", 3, 9.99m);   // 29.97
        _cart.ApplyCoupon("SAVE10");          // 29.97 * 0.90 = 26.973

        Assert.AreEqual(26.97m, _cart.CalculateTotal());
    }

    // ───── End-to-end scenario ─────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("WIDGET", 4, 12.50m);  // 50
        _cart.AddItem("GIZMO", 1, 25.00m);   // 25
        _cart.RemoveItem("GIZMO");
        _cart.ApplyCoupon("SAVE20");          // 50 * 0.80 = 40

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
        Assert.AreEqual(1, _cart.Items.Count);
    }
}

